import React, { useState } from 'react';
import './Works.css';

function Works() {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');

  // 外部リンク例をもとにしたダミーデータ30件
  const dummyWorks = Array.from({ length: 30 }, (_, i) => ({
    id: i + 1,
    title: `グッズ${i + 1}`,
    category: i % 2 === 0 ? 'anime' : 'manga',
    url: i % 2 === 0
      ? 'https://shop.asobistore.jp/category/10107/'
      : 'https://list.amiami.jp/top/search/list?s_originaltitle_id=36257&pagecnt=40&getcnt=0&pagehnt=2',
  }));

  const filteredWorks = dummyWorks.filter(work => {
    const matchesSearch = work.title.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'all' || work.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="works-container">
      <div className="search-section">
        <h2>作品名から探す</h2>
        <div className="search-controls">
          <input
            type="text"
            placeholder="作品名を入力..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
            className="category-select"
          >
            <option value="all">すべて</option>
            <option value="anime">アニメ</option>
            <option value="manga">漫画</option>
          </select>
        </div>
      </div>
      <div className="works-grid">
        {filteredWorks.map(work => (
          <a
            className="work-card"
            key={work.id}
            href={work.url}
            target="_blank"
            rel="noopener noreferrer"
          >
            <div className="work-image">
              <div className="placeholder-image"></div>
            </div>
            <div className="work-info">
              <h3 className="work-title">{work.title}</h3>
              <span className="work-category">
                {work.category === 'anime' ? 'アニメ' : '漫画'}
              </span>
            </div>
          </a>
        ))}
      </div>
      {filteredWorks.length === 0 && (
        <div className="no-results">
          <p>該当する作品が見つかりませんでした。</p>
        </div>
      )}
    </div>
  );
}

export default Works;
